import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../api/client';
import AppNavbar from '../../components/AppNavbar';
import ClosedTickets from '../../components/ClosedTickets';

export default function DeveloperDashboard() {
  const navigate = useNavigate();
 const [ticketIdSearch, setTicketIdSearch] = useState('');
  const [departmentFilter, setDepartmentFilter] = useState('');
  const [divisionSearch, setDivisionSearch] = useState('');
  const [moduleFilter, setModuleFilter] = useState('');
  const [submoduleFilter, setSubmoduleFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [tickets, setTickets] = useState([]);
  const [summary, setSummary] = useState({
    total: 0,
    open: 0,
    reopened: 0,
    closed: 0,
  });

  const [page, setPage] = useState(1);
  const [count, setCount] = useState(0);
  const [nextPage, setNextPage] = useState(null);
  const [previousPage, setPreviousPage] = useState(null);
  const [error, setError] = useState('');



  const loadSummary = async () => {
    try {
      const res = await api.get('/dashboard/summary/');
      setSummary({
        total: res.data.total || 0,
        open: res.data.open || 0,
        reopened: res.data.reopened || 0,
        closed: res.data.closed || 0,
      });
    } catch (err) {
      console.error('Failed to load developer summary', err);
    }
  };

  const loadTickets = async (
    pageNo = page,
    searchValue = search,
    statusValue = statusFilter
  ) => {
    try {
      const params = { page: pageNo };

      if (searchValue) params.search = searchValue;
      if (statusValue) params.status = statusValue;

      const res = await api.get('/tickets/', { params });

      setTickets(res.data.results || []);
      setCount(res.data.count || 0);
      setNextPage(res.data.next);
      setPreviousPage(res.data.previous);
      setError('');
    } catch (err) {
      console.error(err);
      setError('Failed to load developer tickets');
      setTickets([]);
    }
  };

  useEffect(() => {
    loadSummary();
  }, []);

  useEffect(() => {
    loadTickets(page);
  }, [page]);

  const handleApplyFilters = () => {
    setPage(1);
    loadTickets(1, search, statusFilter);
  };

  const handleUpdate = async (ticketId, status, developerRemark) => {
    try {
      await api.post(`/tickets/${ticketId}/developer_update/`, {
        status,
        developer_remark: developerRemark,
      });

      loadSummary();
      loadTickets(page, search, statusFilter);
    } catch (err) {
      console.error(err);
      alert('Failed to update ticket');
    }
  };

  const handleView = (ticketId) => {
    navigate(`/developer/ticket/${ticketId}`);
  };

  const totalPages = Math.ceil(count / 8);

  return (
    <>
      <AppNavbar />

      <div className="container mt-4">
        <h2 className="mb-4">Developer Dashboard</h2>

        {error && <div className="alert alert-danger">{error}</div>}

        <div className="row mb-4">
          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Total Tickets</h5>
                <h2>{summary.total}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Open Tickets</h5>
                <h2>{summary.open}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Reopened</h5>
                <h2>{summary.reopened}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Closed</h5>
                <h2>{summary.closed}</h2>
              </div>
            </div>
          </div>
        </div>

        <div className="card mb-4">
          <div className="card-body">
            <h4 className="mb-3">Tickets Sent to Development</h4>

            <div className="row g-2 mb-3">
              <div className="col-md-6">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Search by Ticket ID / Department / Division / Module / Status"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
              </div>

              <div className="col-md-4">
                <select
                  className="form-select"
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                >
                  <option value="">All Status</option>
                  <option value="Sent to Developer">Sent to Developer</option>
                  <option value="Developer In Progress">Developer In Progress</option>
                  <option value="Reopened">Reopened</option>
                </select>
              </div>

              <div className="col-md-2">
                <button
                  className="btn btn-primary w-100"
                  onClick={handleApplyFilters}
                >
                  Apply
                </button>
              </div>
            </div>

            <div className="table-responsive">
              <table className="table table-bordered table-striped">
                <thead>
                  <tr>
                    <th>Ticket ID</th>
                    <th>Department</th>
                    <th>Division</th>
                    <th>Module</th>
                    <th>Submodule</th>
                    <th>Subject</th>
                    <th>Created Date</th>
                    <th>Status</th>
                    <th>Support Remark</th>
                    <th>View</th>
                    <th>Developer Remark</th>
                    <th>Closed Date</th>
                    <th>Update</th>
                  </tr>
                </thead>

                <tbody>
                  {tickets.length > 0 ? (
                    tickets.map((ticket) => (
                      <tr key={ticket.id}>
                        <td>{ticket.ticket_id}</td>
                        <td>{ticket.department_name || ''}</td>
                        <td>{ticket.division_name || ''}</td>
                        <td>{ticket.module_name || ''}</td>
                        <td>{ticket.submodule_name || ''}</td>
                        <td>{ticket.subject}</td>

                        <td>{ticket.created_at
                            ? new Date(ticket.created_at).toLocaleString()
                            : ''}
                        </td>
                        <td>{ticket.status}</td>
                        <td>{ticket.support_remark || ''}</td>

                        <td>
                          <button
                            className="btn btn-outline-primary btn-sm"
                            onClick={() => handleView(ticket.id)}
                          >
                            👁
                          </button>
                        </td>

                        <td>
                          <textarea
                            className="form-control"
                            rows="2"
                            defaultValue={ticket.developer_remark || ''}
                            id={`remark-${ticket.id}`}
                          />
                        </td>

                        <td>
                          {ticket.closed_at
                            ? new Date(ticket.closed_at).toLocaleString()
                            : ''}
                        </td>

                        <td>
                          <select
                            className="form-select mb-2"
                            defaultValue={ticket.status}
                            id={`status-${ticket.id}`}
                          >
                            <option value="Sent to Developer">
                              Sent to Developer
                            </option>
                            <option value="Developer In Progress">
                              Developer In Progress
                            </option>
                            <option value="Reopened">Reopened</option>
                            <option value="Closed">Closed</option>
                          </select>

                          <button
                            className="btn btn-primary btn-sm"
                            onClick={() =>
                              handleUpdate(
                                ticket.id,
                                document.getElementById(`status-${ticket.id}`).value,
                                document.getElementById(`remark-${ticket.id}`).value
                              )
                            }
                          >
                            Update
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="12">No development tickets available</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            <div className="d-flex justify-content-between align-items-center mt-3">
              <div>
                Total Tickets: <strong>{count}</strong>
              </div>

              <div className="d-flex align-items-center gap-2">
                <button
                  className="btn btn-outline-secondary"
                  disabled={!previousPage}
                  onClick={() => setPage((prev) => prev - 1)}
                >
                  Previous
                </button>

                <span>
                  Page <strong>{page}</strong> of{' '}
                  <strong>{totalPages || 1}</strong>
                </span>

                <button
                  className="btn btn-outline-secondary"
                  disabled={!nextPage}
                  onClick={() => setPage((prev) => prev + 1)}
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </div>

        <ClosedTickets />
      </div>
    </>
  );
}
